using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;

public class ReportController : Controller
{
    // --- FILE EXPORT ---
    // Response.End() is gone in .NET 8. Return a FileContentResult instead.
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();
        var bytes = System.Text.Encoding.UTF8.GetBytes(data);
        return File(bytes, "text/csv", "report.csv");
    }

    // --- REDIRECT WITH AUTH CHECK ---
    // Response.Redirect(url, true) called Thread.Abort internally.
    // In ASP.NET Core, just return RedirectResult — no abort, no exception.
    [HttpPost]
    public IActionResult ProcessAndRedirect()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // ThreadAbortException catch block is REMOVED entirely —
        // Redirect() no longer throws. Catching OperationCanceledException
        // is only needed if ProcessRequest does cancellable async work.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport() => "col1,col2\nval1,val2";
    private void ProcessRequest() { /* business logic */ }
    private void LogError(Exception ex) { /* logging */ }
}

